export const getGetCampaignMeasurementsUrl = (id: string,
    params?: GetCampaignMeasurementsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/v1/campaigns/${id}/measurements?${stringifiedParams}` : `/api/v1/campaigns/${id}/measurements`
}

